def migrate_faq_responses(apps, schema_editor):
    FAQ = apps.get_model('core', 'FAQ')
    FAQResposta = apps.get_model('core', 'FAQResposta')
    for faq in FAQ.objects.all():
        if faq.resposta and not faq.respostas.exists():
            FAQResposta.objects.create(
                faq=faq,
                ordem=0,
                texto=faq.resposta
            )


def update_system_prompts(apps, schema_editor):
    MensagensConfig = apps.get_model('core', 'MensagensConfig')
    from core.mensagens_defaults import DEFAULT_SYSTEM_PROMPT
    for cfg in MensagensConfig.objects.all():
        cfg.system_prompt = DEFAULT_SYSTEM_PROMPT
        cfg.save()


